在Android上获取日志的核心组件是logd守护进程。logcat命令就是使用logd来获取设备上的日志信息。如果想要自己编写获取日志的程序，就需要使用以下API：

1. ```android.util.Log```类：用于在应用程序中输出日志。

2. ```android.os.SystemClock```类：用于测量代码的执行时间。

3. ```android.os.Process```类：用于获取应用程序的进程ID。

4. ```android.os.Parcel```类：用于序列化和反序列化Java对象。

5. ```android.os.MemoryFile```类：用于在进程间共享内存。

6. ```liblog```库：用于与logd守护进程通信。

以下是一个简单的代码示例，它可以获取Android设备上的所有日志：

```c++
#include <sys/socket.h>
#include <sys/un.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <errno.h>
#include <sys/uio.h>
#include <sys/types.h>
#include <fcntl.h>

#define LOG_TAG "MyLog"
#define LOG_SOCKET "/dev/socket/logdw"

int main(int argc, char **argv) {

    // 创建Unix Domain Socket连接
    int sockfd;
    struct sockaddr_un addr;
    memset(&addr, 0, sizeof(addr));
    addr.sun_family = AF_UNIX;
    strcpy(addr.sun_path, LOG_SOCKET);

    if ((sockfd = socket(AF_UNIX, SOCK_STREAM, 0)) == -1) {
        return -1;
    }

    // 连接到logd守护进程
    if (connect(sockfd, (struct sockaddr *)&addr, sizeof(addr)) == -1) {
        return -1;
    }

    // 发送日志请求
    char buf[1024];
    sprintf(buf, "dump 1 %d * *", getpid());
    if (write(sockfd, buf, strlen(buf) + 1) == -1) {
        return -1;
    }

    // 读取并输出日志
    struct iovec iov[2];
    iov[0].iov_base = buf;
    iov[0].iov_len = sizeof(buf);
    iov[1].iov_base = "\0";
    iov[1].iov_len = 1;

    int fd = open(LOG_SOCKET, O_RDONLY | O_NONBLOCK);
    ssize_t ret = readv(fd, iov, 2);

    while (ret >= 0) {
        if (ret > 0) {
            fprintf(stdout, "%s", (char *)iov[0].iov_base);
        }
        ret = readv(fd, iov, 2);
    }

    if (ret == -1) {
        if (errno == EINTR) {
            return 0;
        }
    }

    return 0;
}
```

请注意，在使用以上代码时，需要先在设备上获得相应的权限，例如：```
adb shell chmod 777 /dev/socket/logdw```。

