这个错误通常是因为程序使用的 socket() 中的第三个参数（即 socket 类型）与服务器端 socket 的类型不一致。在这个 case 中，程序中使用的是 SOCK_STREAM 客户端套接字类型，而在服务器端，我们需要先打开 /dev/socket/logdw 的 Unix 套接字，并在服务器端代码中使用它。

这种情况下，服务器端需要使用 SOCK_SEQPACKET (sequential packet) 套接字类型。请尝试使用以下代码：

```c++
#include <sys/socket.h>
#include <sys/un.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <errno.h>
#include <sys/uio.h>
#include <sys/types.h>
#include <fcntl.h>

#define LOG_TAG "MyLog"
#define LOG_SOCKET "/dev/socket/logdw"

int main(int argc, char **argv) {

    // 创建 Unix Domain Socket 连接
    int sockfd;
    socklen_t len;
    struct sockaddr_un addr;

    if ((sockfd = socket(AF_UNIX, SOCK_SEQPACKET, 0)) == -1) {
        perror("socket");
        exit(EXIT_FAILURE);
    }

    // 与 logd 守护进程建立连接
    memset(&addr, 0, sizeof(addr));
    addr.sun_family = AF_UNIX;
    strncpy(addr.sun_path, LOG_SOCKET, sizeof(addr.sun_path) - 1);

    len = sizeof(addr.sun_family) + strlen(addr.sun_path) + 1;
    if (connect(sockfd, (struct sockaddr *)&addr, len) == -1) {
        perror("connect");
        exit(EXIT_FAILURE);
    }

    // 向 logd 请求日志信息
    char buf[1024];
    sprintf(buf, "dump 1 %d * *", getpid());
    if (write(sockfd, buf, strlen(buf) + 1) == -1) {
        perror("write");
        exit(EXIT_FAILURE);
    }

    // 读取并输出日志信息
    struct iovec iov[2];
    iov[0].iov_base = buf;
    iov[0].iov_len = sizeof(buf);
    iov[1].iov_base = NULL;
    iov[1].iov_len = 0;

    int fd = open(LOG_SOCKET, O_RDONLY | O_NONBLOCK);
    ssize_t ret = readv(fd, iov, 2);

    while (ret >= 0) {
        if (ret > 0) {
            fprintf(stdout, "%s", (char *)iov[0].iov_base);
        }
        ret = readv(fd, iov, 2);
    }

    if (ret < 0) {
        if (errno == EINTR) {
            return 0;
        }
    }

    return 0;
}
```

